var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"여어, <color=#ffd34c>황무지의 여우</color>. 오랜만이네.","JPN":"よお、<color=#ffd34c>荒れ地の狐</color>。久しぶりやな。","ENG":"Howdy, <color=#ffd34c>Wasteland Fox</color>. Haven’t seen ya in a while.","TWN":"喂，<color=#ffd34c>荒野狐狸</color>，好久不見。"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"그러는 너는…… 세 가지 속성을 다루는 <color=#ffd34c>미리네★스타라이트</color>인가?","JPN":"お前は……三つの属性を操る<color=#ffd34c>マリ★スターライト</color>か？","ENG":"Y-you’re... <color=#ffd34c>Mi Rinae★Starlight</color>, the wielder of the three elements!","TWN":"你是……可以操控三種屬性的<color=#ffd34c>宓璃奈★星光</color>？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"뭔데, 그게!?","JPN":"何だよ、それ！？","ENG":"What’s that supposed to mean?","TWN":"什麼鬼？完全沒聽過啊！？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후, 섣부르게 움직이지 않는 편이 좋을낀데?","JPN":"ふふ、うかつに動かんほうがええと思うで？","ENG":"Heh, I reckon ya better stay right where ya are...","TWN":"呵呵，勸你還是不要輕舉妄動唄？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아무리 황무지의 여우라캐도 불 속성 참격의 도트 데미지…… 그거 쪼매 아플끼다.","JPN":"いくら荒れ地の狐や言うても、炎属性斬撃のドットダメージ……ちょっと痛いからな。","ENG":"Not even Wasteland Fox can handle damage-over-time pyro damage... I reckon your wound feels hotter than a burnin’ stump.","TWN":"就算是荒野狐狸，遇到火屬性斬擊的連續傷害……也是會有點痛的。"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"평범하게 빗자루로 때려 놓고 무슨 불속성이냐고!","JPN":"普通にほうきで殴っておいて何が炎属性だよ！","ENG":"You just hit him with a broom! What pyro damage?!","TWN":"不就是拿一根掃把打人，哪來的火屬性啦！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"큭, 확실히 베인 곳이 화끈화끈하군. 썩 나쁘지 않은 참격이었어.","JPN":"くっ、確かに斬られたところがヒリヒリする。なかなか悪くない斬撃だった。","ENG":"Kggh, it really does feel like my wounds are burning. Not bad, Starlight.","TWN":"唔，被砍到的地方確實有點熱熱的，斬得漂亮！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"아니, 그러니까 그런 거 일일이 받아주지 마!","JPN":"いや、だからそんなのにいちいち反応するなよ！","ENG":"Don’t play along with her absurdity!","TWN":"喂，你還接得下去喔！？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"어라, 불속성? 무슨 소리야? 방금 평범하게 빗자루를…….","JPN":"あれ、炎属性？　どういうことだ？　今普通にほうきを……","ENG":"Huh? Fire element? But it was just an ordinary broom...","TWN":"什麼火屬性？在說什麼？不就是一根平凡的掃把……"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"너, 이 자식! 지금 코미페의 금기를 어길 셈이냐?","JPN":"お前！　コミフェの禁忌を破るつもりなのか？","ENG":"You, you prick! You dare break the sacred rule of Comic Festival?","TWN":"臭小子！你現在是打算觸犯動漫展的禁忌嗎？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"그, 금기요?","JPN":"き、禁忌ですか？","ENG":"S-sacred rule?!","TWN":"什…什麼禁忌？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"그래! 여기서는 다른 사람의 설정에 트집을 잡으면 안 된다고 했잖아!","JPN":"そうだ！　ここでは他人の設定に口を出したらダメだって言っただろ！","ENG":"Yes, rule! You’re not supposed to doubt other people’s characters!","TWN":"我不是說過！不能戳破別人的人設！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥? 뭐라고? 불꽃이 안 나왔다고? 그럴 리가 없는데? 잘 못 본 거 아이가?","JPN":"ええ？　何やて？　炎が出なかった？　そんなはずないんやけどな？　見間違いじゃあらへん？","ENG":"Huh?! What’s that now? No fire? Can’t be! Ya must have missed it!","TWN":"啥？你說啥？你說沒看到火花？怎麼可能？是不是你眼花唄？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 알았다! 내 다시 함 해볼게!","JPN":"へへっ、わかったわ！　もっかいやってみるわ！","ENG":"Heh, alrighty! Let me demonstrate for you folks again!","TWN":"嘿嘿，那好唄！我再施展一次唄！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L24_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"아, 알겠어! 알겠다고!","JPN":"わ、わかった！　わかったから！","ENG":"O-okay! Fine! We get it!","TWN":"有…有啦！我有看到！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"이번에는 분명히 나오는 거 봤어! 부, 불꽃!","JPN":"今度は確かに出るの見えたよ！　ほ、炎！","ENG":"I definitely saw you flame this time! F-fwoosh!","TWN":"這次真的看到了啦！有…有火花！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_C","text":{"KOREA":"마…… 맞아! 나도 봤으니까……! 이제 그만…….","JPN":"そ……そうだ！　俺も見たから……！　もうやめろ……","ENG":"Y-yeah! I saw it too...! So no more...","TWN":"對……對啊！我也有看到……！別再打了……"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"대, 대단해…….","JPN":"す、すごい……","ENG":"A-amazing...","TWN":"好…厲害……"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"저 누나, 빗자루 하나로 성인 남자 두 명을 굴복시켰어.","JPN":"あのお姉さん、ほうき一本で男の大人を二人もひざまずかせた。","ENG":"That girl just took down two grown men with a broomstick.","TWN":"那位姊姊竟然只用一支掃把，就讓二位成年男性求饒！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭔소리고? 방금 건 빙결 속성이었는데? 니들 지금 꽁꽁 얼어서 못 움직인다 아이가.","JPN":"何言ってるん？　さっきのは氷結属性やったのに。あんたたち、今キンキンに凍って動けへんやろ？","ENG":"What? That was cryo just now! Y’all ain’t goin’ nowhere cuz you're frozen!","TWN":"什麼？剛剛是冰屬性欸？你們現在應該不能動才對唄！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"비, 빙결 속성? 그게 무슨 억지…….","JPN":"ひょ、氷結属性？　何ふざけたことを……","ENG":"C-cryo? Don't be ridiculous–","TWN":"冰…冰屬性？胡扯什麼……"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"억지? 지금 억지라고 했나?","JPN":"ふざけた？　今ふざけたって言うたか？","ENG":"WHAT?! What did you just say to me?","TWN":"什麼？你說我胡扯？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"저기서 무슨 싸움 같은 게 일어났나 봐. 왠지 흥미진진한데?","JPN":"あっち、何かあそこケンカしてるみたい。何か気になるわ。","ENG":"I think there’s some kind of fight going on over there. Seems intense.","TWN":"那邊好像有人在打架欸？感覺很精彩。"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"에이, 합을 맞춘 퍼포먼스 같은 거겠지. 여기 코미페잖아.","JPN":"ええ～？　呼吸を合わせたパフォーマンスみたいなものでしょ。ここコミフェだし。","ENG":"Nah, it’s probably some kind of show. We’re at Comic Festival, after all.","TWN":"拜託，那都是Set好的啦～"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"이 이상 내 동료들에게 손 대는 것은 용서할 수 없다, 미리네★스타라이트.","JPN":"これ以上俺の仲間に手を出すのは許さん、マリ★スターライト。","ENG":"I won’t allow any more violence towards my comrades, Mi Rinae★Starlight.","TWN":"你再打我的夥伴，我就不客氣囉，宓璃奈★星光！"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호, 지금 한 번 해보자는기가? 황무지의 여우.","JPN":"ほう何や、一発やろう言うとんのか？　荒れ地の狐。","ENG":"Aha, now things are gettin’ spicy here. Bring it on, Wasteland Fox.","TWN":"喔呵？現在是要打一場的意思嗎，荒野狐狸？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"잠깐! 두 사람 다 도대체 왜 싸우려는 건데요?","JPN":"ちょっと！　二人とも、喧嘩はやめてください！","ENG":"Wait! Why are you so obsessed with fighting each other?!","TWN":"先等一下！你們二個現在到底幹嘛要打架啦？"},"stage":{"bg":"AIRDOME","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으응? 뭔소리고?","JPN":"うん？　何言うてんねん？","ENG":"Huh? What's that now?","TWN":"啥？什麼意思？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니 점마들한테 괴롭힘 당하고 있는 거 아니었나? 내는 니 구해줄라캤는데?","JPN":"あんた、あいつらにいじめられてるんやなかったん？　ウチはあんたを助けようと思ったんだけやねんけど。","ENG":"Weren’t ya being jumped by these nitwits? I was trying to save ya!","TWN":"他們不是在欺負你嗎？我這是在為你打抱不平唄？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"무슨 소리지? 우린 그냥 이 소년에게 코미페를 안내해주려는 것뿐이었다.","JPN":"何を言ってるんだ？　俺たちはただ、この少年にコミフェを案内してやろうとしただけだぞ。","ENG":"What are you talking about? We were simply trying to show him around the place.","TWN":"你在胡說什麼？我們只是要帶他認識動漫展而已！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥? 그런기가?","JPN":"ええっ？　そうなん？","ENG":"Aah? Is that so?","TWN":"啥？是喔？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"진작 말을 하지, 미안타. 내는 몰랐데이.","JPN":"先に言うてや。誤解してごめんな。","ENG":"Y’all should've told me sooner! Sorry, fellas. Hadn’t a clue!","TWN":"不早說～誤會一場，抱歉啦。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"아니 이쪽이야말로 사과하지.","JPN":"いや、こちらこそ悪かった。","ENG":"No, it’s me who owes you an apology.","TWN":"不，我們才該道歉，"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"다른 사람의 취미와 취향을 존중한다는 룰을 어기고 말았으니까 말이지.","JPN":"他人の趣味と好みを尊重するというルールを破ってしまったからな。","ENG":"I broke the rule of respecting diversity and creativity.","TWN":"因為我們破壞要尊重他人興趣的規則。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 괘안타 괘안타. 내는 기분 하나도 안 상했다.","JPN":"へへっ、大丈夫やで、大丈夫。ウチは全然平気。","ENG":"Heh, I can sit with it. I feel fine as cream gravy, don’t worry!","TWN":"嘿嘿，沒事沒事，我完全沒受傷。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"후후, 그럼 승부는 다음으로 미뤄두어야겠군. 미리네★스타라이트.","JPN":"ふふ、それでは勝負は次回にお預けだな。マリ★スターライト。","ENG":"Ha ha, then I guess we’ll have to put our battle on hold for now... Mi Rinae★Starlight.","TWN":"呵呵，那就下次再一較高下囉，宓璃奈★星光。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후, 얼마든지 덤비라. 황무지의 여우.","JPN":"ふふ、いくらでもかかって来いや。荒れ地の狐。","ENG":"Heh, you're welcome anytime... Wasteland Fox.","TWN":"呵呵，放馬過來唄，荒野狐狸。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"이, 이런 게…… 코미페?","JPN":"こ、これが……コミフェ？","ENG":"Is this what Comic Festival is like...?","TWN":"這…這就是…動漫展？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"왠지 상상했던 거랑…… 조금 다른 것 같은데……?","JPN":"なんか想像してたのと……ちょっと違うような……？","ENG":"It surely is... different from what I imagined...","TWN":"怎麼和我想像中的……不太一樣……？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 꼬맹이. 니 괘안나? 다친 데는 없고?","JPN":"なあ、じゃりんこ。あんた大丈夫か？　ケガはないよな？","ENG":"Hey, kiddo! Everything fine over there? No injuries?","TWN":"喂，小朋友，你沒事唄？有受傷嗎？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"애초에 위험하지도 않았거든요.","JPN":"そもそも危なくもなかったんですけど。","ENG":"I wasn’t in danger in the first place.","TWN":"我根本就沒有身陷危險過。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……으음?","JPN":"……ううん？","ENG":"...Hmm?","TWN":"……啥？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아아앗!? 꼬맹이, 니 그 게임팩, 스트리트 카운터 아이가!?","JPN":"あああっ！？　じゃりんこ、あんたそのカセット、ストリート・カウンターやんか！？","ENG":"Aaaah?! Kid, that game pack... Ain’t it Street Counter?!","TWN":"喔喔喔！？小朋友，你手上的遊戲片是街頭制裁者嗎！？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……어!?","JPN":"……え！？","ENG":"...Oh?!","TWN":"……嗯！？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그거 게임팩 버전은 완전 귀할낀데? 물량이 없어서 내도 실물은 구경도 못해봤다!","JPN":"それ、カセットバージョンはめちゃくちゃ貴重やん。あんま出回ってへんから、ウチも本物は初めて見たわ！","ENG":"Gosh! That version's rarer than gold! I haven’t even had the chance to see one in person!","TWN":"那個遊戲片超珍貴的欸？因為數量稀少，我都沒親眼見過呢！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"누나도 스트리트 카운터 아시는구나! 이거 진짜 명작이라고요!","JPN":"お姉さんもストリート・カウンターを知ってるんですね！　これ、本当に名作なんですよ！","ENG":"You know this too? Street Counter is a masterpiece!","TWN":"這位姊姊也知道街頭制裁者喔！這個真的超好玩的！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그쟈! 그쟈!","JPN":"そう！　そう！","ENG":"Hear, hear!","TWN":"沒錯沒錯！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"가만보니 그 박스 가면…… 그거 샐러리맨 고증 아이가? 오호, 까리한데?","JPN":"そういえばそのダンボールの仮面……それ、サラリーマンのやろ？　へえ、カッコええやん。","ENG":"Wait a minute... Ain’t that mask Salaryman’s thing? Pretty cool!","TWN":"現在仔細一看，你戴的紙箱面具……是上班族X戴的面具吧？細節都有講究欸，超酷的唄！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"맞아요! 맞아요!","JPN":"そうです！　そうなんです！","ENG":"Yes! Yes!","TWN":"沒錯沒錯！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"저 말고 실제로 스카 하는 사람 실제로 처음 봐요, 누나!","JPN":"僕以外に実際にストカウプレイしてる人は初めて見ましたよ、お姉さん！","ENG":"You’re the first person I’ve met who actually plays Street Counter!","TWN":"我還是第一次遇到有在玩＂街制＂的人欸，姊姊！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"오래된 게임이고…… 물량도 별로 없어서 팬덤이 작긴 하지만……","JPN":"古いゲームだし……ソフトも出回ってなくてファンは少ないですけど……","ENG":"It’s such an old game... Not to mention a smaller fandom due to insufficient stock...","TWN":"這是很老的遊戲……發行量也不多，粉絲圈也很小……"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 팬덤이 뭔 상관인데? 그냥, 니가 좋아하면 그걸로 된 거 아이가?","JPN":"何？　ファンなんて関係あらへん。ただ、あんたが好きならそれでええんやで？","ENG":"Ah? What’s that? It’s ain’t about the fandom size, kiddo! All that matter is if ya like it, right?","TWN":"然後呢？粉絲圈很小又怎樣？只要你喜歡就好啦？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그건 그렇지만…….","JPN":"それはそうですけど……","ENG":"Sure, but still...","TWN":"話是沒錯……"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L35_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……흐음.","JPN":"……ふーん。","ENG":"...Hmm.","TWN":"……嗯嗯。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L36_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이건 비밀이긴 한데…… 뭐, 스카 팬이라면 상관없나?","JPN":"これは秘密なんやけど……ま、ストカウのファンなら大丈夫やろか？","ENG":"Alrighty, let me share a little secret with ya... Maybe it won’t matter, since you’re already Street Counter fan.","TWN":"我跟你說個秘密……反正都是\\"街制\\"的粉絲應該沒關係唄？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"네? 비밀이라고요?","JPN":"え？　秘密？","ENG":"Huh? A secret?","TWN":"蛤？什麼秘密？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 니 오늘 윽수로 운이 좋네.","JPN":"へへっ、あんた、今日めっちゃついてるわ。","ENG":"Heh, ya drew the best bull today, kiddo!","TWN":"嘿嘿，你今天超幸運的！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사실 스카 제작한 사람, 그거 우리 쌤이거든.","JPN":"実はストカウを制作した人、ウチの先生やねん。","ENG":"The person who made Street Counter... is my teach!","TWN":"其實”街制\\"的製作人是我們老師唄！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 오늘 코미페에 오신다캤다.","JPN":"へへっ、今日コミフェに来るって言うとったわ。","ENG":"Heh, he said he’ll be droppin’ by today.","TWN":"嘿嘿，他說他今天會來動漫展。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우얄래? 내랑 쌤 한 번 보러 갈래? 스카 팬이라카믄 쌤도 좋아하실끼다.","JPN":"どうする？　ウチと先生に会いに行く？　ストカウのファンなら先生も喜ぶと思うけどな。","ENG":"How does that sit with ya? Ya wanna tag along and meet him? I reckon he’ll be delighted to see a fan.","TWN":"怎麼樣？你要和我去見老師嗎？如果是\\"街制\\"粉絲的話，那老師看到你應該也會很開心唄？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"처음부터 이상한 사람이라고 생각하긴 했는데…….","JPN":"最初から変な人だとは思ったけど……","ENG":"There was something off about her from the start...","TWN":"從剛才就覺得這個人怪怪的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"오타쿠를 상대로 하는 새로운 종교 권유인가?","JPN":"オタク相手の新手の宗教勧誘なんじゃ？","ENG":"Is this some sort of new cult that targets otakus?","TWN":"難道是專門找御宅族下手的新興宗教組織？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"괜히 따라갔다가……. 무서운 형들이 기다리고 있으면 어떡하지?","JPN":"下手について行って……怖い人たちが待ってたらどうしよう？","ENG":"What happens if I follow her? Will there be thugs waiting for me...?","TWN":"萬一我跟著她去之後……遇到可怕的大哥怎麼辦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 반응이 와 그 모양이고? 지금 못 믿겠다 이기가?","JPN":"何や？　なんでそんな反応やねん？　ウチの言うこと信じられへんのか？","ENG":"Ah? What’s that face you're pulling? Ya don’t believe me?","TWN":"做啥？你那是什麼反應？是不相信我嗎？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"아, 아니에요! 믿어요, 믿어! 하하.","JPN":"ち、違います！　信じます、信じてますよ！　はは。","ENG":"Y-yes, I do! I do believe you. Ha ha.","TWN":"沒…沒有啦！我信我信！哈哈。"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"아, 그러고보니 저……","JPN":"あ、そういえば僕……","ENG":"Oh, come to think of it...","TWN":"那個，話說回來……"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"코미페 때문에 슬슬 줄 서러 가봐야 할 것 같아요! 그럼 이만!","JPN":"コミフェでそろそろ列に並ばないと！　それじゃあ！","ENG":"I should go and stand in line! Bye!","TWN":"我要趕快去排隊入場！我先走囉！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"줄이라고? 그런 걸 와 기다리는데?","JPN":"列？　なんでそんなとこで待ってんねん。","ENG":"Line? Why would you do such a thing?","TWN":"排隊？做啥要排隊？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 마, 그냥 잔말 말고 따라 온나! 내만 믿으면 다 된다!","JPN":"へへっ、まあ、ごちゃごちゃ言わんとついて来いや！　ウチのことを信じればええ！","ENG":"Heh, leave that aside and follow me! Trust me, you're in good hands.","TWN":"嘿嘿，喂，廢話少說，跟我來！信我準沒錯唄！"},"stage":{"bg":"AIRDOME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"우와…… 여, 여기가 코미페 행사장 내부?","JPN":"うわ……こ、ここがコミフェ会場の内部？","ENG":"Wow... S-so this is what it looks like inside...","TWN":"哇……這裡就是動漫展現場嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"생각했던 것보다 훨씬 넓어! 그리고 더워!","JPN":"思ったよりずっと広い！　それに暑い！","ENG":"It’s even bigger than I thought! And it’s really hot!","TWN":"比我想像中還要寬敞，而且好熱喔！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"뭔가 흐릿한 안개 같은 것도 끼어있고……!","JPN":"なんかモヤモヤした霧なんかもあるし……！","ENG":"It’s kind of foggy in here...!","TWN":"怎麼好像霧濛濛的……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 꼬맹이 니 여 처음이가?","JPN":"何や、じゃりんこ。あんた、ここ初めてなん？","ENG":"What’s that? Is it your first time here, kiddo?","TWN":"什麼嘛？你是第一次來喔？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 11월인데도 후끈하제? 다들 밤새서 만든 회지를 들고나와 팔고 있는 것인기라.","JPN":"へへっ、11月なのに暑いやろ？　みんな徹夜で作った同人誌を持ってきて売ってるんやで。","ENG":"Heh, pretty steamy for a November day, ain’t it? They’re all here, with their fanbooks that they’ve been workin’ on for so long.","TWN":"嘿嘿，明明是11月卻還是很熱唄？大家都是熬夜把作品做好拿出來賣的。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"원래 꿈을 가진 사람은 저마다 반짝반짝 열을 내거든.","JPN":"もともと夢を持ってる人は、それぞれキラキラと情熱持って頑張ってんねん。","ENG":"Folks with dreams inside their hearts emit light and heat like them stars do!","TWN":"有夢想的人都會像他們那樣發光發熱唄。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 별들이 별무리처럼 여기 코미페에 모여있다고 생각하믄 꽤 두근두근하지 않나?","JPN":"そんな星が星群みたいに、ここコミフェに集まってるって思ったら結構ドキドキせえへん？","ENG":"Ain’t it touching, seein’ all these beautiful stars gathered up at Comic Festival?","TWN":"而那群星星聚集在動漫展這裡，不覺得光想到就令人很興奮嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내는 그래서 여가 좋다.","JPN":"だからウチはここが好きやねん。","ENG":"That’s why I like it here a lot.","TWN":"所以我很喜歡這裡。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"이상한 사람인 줄 알았는데…… 누나 꽤 멋진 말도 할 줄 아시네요.","JPN":"変な人だと思ったけど……お姉さん、結構カッコいいことも言うんですね。","ENG":"I thought you were a weirdo... But what you said just now is pretty cool.","TWN":"我還以為姊姊是怪人……沒想到你也會說這麼感人的話。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 뭐라노.","JPN":"へへっ、何言うてんの。","ENG":"Heh heh. Aw shucks.","TWN":"嘿嘿，過獎囉。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"어? 그런데 저희 이렇게 줄 안 서고 이렇게 막 뒷문으로 들어와도 돼요?","JPN":"え？　でも僕たち、列に並ばずに裏口から入ってきちゃっても大丈夫なんですか？","ENG":"Huh? Are we allowed to use the back door? I thought we were supposed to line up.","TWN":"不過，我們可以這樣不排隊，直接從後門進來嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"여긴 부스참가자 전용 입구라고 써있던데?","JPN":"ここブース参加者専用入口って書いてあるんですけど…？","ENG":"It had \\"Exhibitor Entry Only\\" written on it...","TWN":"上面寫這裡是參展人員專屬入口欸？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아 그거? 별로 상관없다.","JPN":"あ、それ？　別に関係あらへん。","ENG":"Oh, that? No worries, kiddo.","TWN":"喔，是喔？無所謂啦。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"왜냐하믄 우리도 일반 참가자 아니거든.","JPN":"なぜなら、ウチらも一般参加者やないし。","ENG":"We’re not here as normal attendees.","TWN":"因為我們又不是一般的參觀人員。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"네에에에에에에에!? 뭘 만드시는데요?","JPN":"ええええええええ！？　何を作ってるんですか？","ENG":"Huhhhh?! What do you make?","TWN":"什麼意思？你在做什麼？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 그건 부스 도착할때까지 비밀이다.","JPN":"へへっ、それはブースに着くまでの秘密やで。","ENG":"That’s goin’ to be a secret ‘till we get there.","TWN":"嘿嘿，秘密，等到攤位後我再跟你說唄。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"빨랑 안따라오고 뭐하노? 떼놓고 간데이.","JPN":"早くついて来いや！　置いて行くで？","ENG":"Aren't ya comin'? Better catch up or ya might get lost.","TWN":"還不快跟上？跟丟我可不管你喔？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아! 쌤! 왜 이렇게 일찍 오셨어요!? 보고 싶었어요, 쌤!","JPN":"うわあ！　先生！　なんでこんな早く来たんですか？！　会いたかったです！","ENG":"Aah! Teach! You’re here early! I missed you so much!","TWN":"哇！老師！你怎麼這麼早到！？我好想你喔，老師！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하. 오셨군요, 리네 양. 다들 기다리고 있었어요.","JPN":"はは。やっと来たね、マリ君。みんな待ってたんだよ。","ENG":"Ha ha, you came, Rinae. We were waiting for you.","TWN":"哈哈，你來啦，璃奈，大家都在等你喔。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_QM","text":{"KOREA":"리네야! 곧 행사 시작인데 왜 이렇게 늦었어, 걱정했잖아. 전화도 안 받고.","JPN":"マリちゃん！　もうすぐ始まるのに、なんで遅刻したのよ？　心配したんだからね。電話にも出ないし。","ENG":"Rinae! The event’s about to start. What took you so long? We were worried sick. You didn’t answer our calls!","TWN":"璃奈！活動都快開始了，你怎麼這麼晚才來，害我擔心死了，電話也不接。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_QM","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_QM","text":{"KOREA":"겨우 끝냈어…… 부스 준비…… 선생님이 도와주셔서.","JPN":"やっと終わった……ブース準備……先生が手伝ってくれて。","ENG":"We finished... the booth... with Teacher’s help.","TWN":"終於弄好了……攤位……多虧有老師的幫忙。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_QM","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헤, 미안타. 다인, 보라야. 대신에……","JPN":"へへ、ごめんな。タエ、シホ。その代わりに……","ENG":"Heh heh. Sorry 'bout that, Dain and Bora. But look...","TWN":"嘿嘿，妲茵、寶拉，對不起嘛。不過你們看……"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"짜잔! 내 이렇게 손님 데려왔데이!","JPN":"じゃじゃーん！　お客さん連れてきたで！","ENG":"Ta da! I’ve brought along a guest!","TWN":"鏘鏘！我有帶客人來喔！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으음? 옆에 그 아이가 손님?","JPN":"ん？　隣の子がお客さん？","ENG":"Mm? You mean that little boy?","TWN":"嗯？旁邊的小朋友就是客人？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……손님? 제가요?","JPN":"……お客さん？　僕がですか？","ENG":"...Guest? Me?","TWN":"……客人？我？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 꼬맹이 니가 놀라면 우짜노?","JPN":"何や？　じゃりんこ、あんたが驚いてどうするん。","ENG":"Ah? What are ya surprised about, kiddo?","TWN":"欸！你這樣就露餡兒啦！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어? 그러고보니 그 가면……. 샐러리맨X의 히어로 마스크로군요!","JPN":"おや？　そういえば、その仮面……サラリーマンXのヒーローマスクだね！","ENG":"Oh? That mask... it's Salaryman X's hero mask!","TWN":"喔？你頭上戴的面具……是上班族X的英雄面具！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"어라? 형도 스트리트 카운터를 알아요?","JPN":"えっ？　お兄さんもストリート・カウンターを知ってるんですか？","ENG":"Huh? You’re into Street Counter too?","TWN":"喔？大哥你也知道街頭制裁者嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그야 모를 리가 없죠. 그 게임 제가 제작한 거니까요.","JPN":"はは、そりゃ当然だよ。そのゲーム、私が作ったんだから。","ENG":"Ha ha, of course, I am. I’m the one who made it, after all.","TWN":"哈哈，怎麼可能不知道，那個遊戲是我做的。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"네!? 그, 그럼…… 미리네 누나가 말한 선생님이라는 분이……!?","JPN":"ええ！？　じゃ、じゃあ……マリさんが言ってた先生って……！？","ENG":"What?! Th-then... You must be the teacher Rinae was talking about...","TWN":"什麼！？所以……宓璃奈姊姊說的老師就是……！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"벌써 발매한지 꽤 오랜 시간이 지난 게임인데…….","JPN":"もう発売してからずいぶん経つゲームだけど……","ENG":"It’s been quite some time since its release...","TWN":"這款遊戲是很久以前發行的……"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여전히 저와 제 동료들이 만든 게임을 즐겨 주셔서 감사하군요.","JPN":"相変わらず私と私の仲間が作ったゲームを楽しんでくれてるとは、ありがたいな。","ENG":"I’m grateful that you still enjoy the game my colleagues and I made together.","TWN":"謝謝你還這麼喜歡我和夥伴們一起製作的遊戲。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"저, 정말로 스카를 제작하신 분이라고요? 하지만 스카의 개발사는 해체됐다고…….","JPN":"ほ、本当にストカウを作った方なんですか？　でも、ストカウの開発会社は倒産したって……","ENG":"Y-you really developed Street Counter? But I heard the company went out of business...","TWN":"您…您真的是\\"街制\\"的製作人嗎？可是我聽說\\"街制\\"的研發團隊已經解散了……"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 뭐 이런저런 사정이 있었죠.","JPN":"はは、まあ、いろんな事情があってね。","ENG":"Ha ha, it’s a long story.","TWN":"哈哈，因為發生一些事情。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 결과적으로 스트리트 카운터라는 게임에 대한 권한은 저한테 있습니다.","JPN":"でも、結果的にストリート・カウンターというゲームに対する権限は私が持っているんだ。","ENG":"But, in the end, I'm the one who owns the rights to Street Counter.","TWN":"不過以結果來說，街頭制裁者的遊戲版權是在我這裡的。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그리고…… 짜잔, 기대하시라!","JPN":"それに……じゃーん！","ENG":"And so... Ta da!","TWN":"而且……鏘鏘，敬請期待！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우리 연구회는 쌤의 허락을 맡아서 스트리트 카운터의 차기작을 맹글고 있다는 말씀!","JPN":"ウチらの研究会は、先生の許可を得てストリート・カウンターの続編を作ってんねんで！","ENG":"Our Research Club is makin’ a smokin’ new sequel of Street Counter, under Teach’s permission!","TWN":"我們社團獲得老師的許可，正在製作街頭制裁者的續作！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이름하야…… <color=#ffd34c>카운터즈 사가</color>!","JPN":"名づけて……<color=#ffd34c>カウンターズ・サーガ</color>！","ENG":"Behold... <color=#ffd34c>Counters Saga</color>!","TWN":"名字就叫……<color=#ffd34c>制裁者傳奇</color>！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"누, 누나들이 스카의 차기작을 만들고 있다고요……? 겨우 세 명이……?","JPN":"み、みなさんでストカウの続編を作ってるんですか……？　たった三人で……？","ENG":"Y-you’re making the sequel of Street Counter...? The three of you...?","TWN":"你…你說你們在制作\\"街制\\"的續作嗎……？就你們三個人……？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 반응이 와 그 모양인데? 니는 시작이 반이라는 말도 모르나?","JPN":"何や、その反応は。思い立ったが吉日って言葉、知らへんの？","ENG":"Ah? What’s that reaction? Don’t ya know the saying, \\"Well begun is half done\\"?","TWN":"做啥？你那是什麼反應？你沒聽過開始是成功的一半嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우리 서브컬처 연구회는 카운터즈 사가를 성공시켜가, 게임계의 미래를 반짝반짝 밝힐끼다!","JPN":"ウチら、サブカルチャー研究会はカウンターズ・サーガを成功させて、ゲーム業界の未来をキラキラと輝かせるんや！","ENG":"We, the Subculture Research Club, will successfully launch Counters Saga and shoot up the industry like a rocket launcher!","TWN":"我們二次元研究社一定會讓制裁者傳奇成功，然後成為遊戲界未來的新星！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니도 스카 팬이라면 함 해보고 싶지 않나?","JPN":"あんたもストカウのファンなら、一度プレイしたいんちゃう？","ENG":"Well? How does that sound? Ain’t you itchin’ to play?","TWN":"身為\\"街制\\"的粉絲，你想體驗看看嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오늘 우리 부스에서는 특별히 카운터즈 사가를 체험해볼 수 있다 안 하나!","JPN":"今日このブースでは、特別にカウンターズ・サーガを体験することができるんやで！","ENG":"Lucky for you, our booth offers a demo version of Counters Saga!","TWN":"今天特別在攤位開放體驗制裁者傳奇喔！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"벌써 테스트 플레이가 가능하다고요?","JPN":"もうテストプレイができるんですか？","ENG":"The demo's already out?!","TWN":"已經可以試玩啦？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L36_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후후, 내는 뻥 안 친다.","JPN":"ふふふ、ウチ嘘は言わへん。","ENG":"Heh heh heh, ya can take that to the bank. I ain’t lyin’!","TWN":"呵呵呵，我是不會騙人的。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어때 꼬맹이? 내랑 겜 한 판 해볼끼가?","JPN":"どうや？　じゃりんこ。ウチと一発勝負してみるか？","ENG":"So, kiddo. What do ya think? Ya reckon you wanna play a set or two with me?","TWN":"怎麼樣，小朋友？要和我比一場嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……좋아요! 해볼게요! 아니, 하게 해주세요!","JPN":"……はい！　やってみます！　いや、やらせてください！","ENG":"...Yes! I’ll do it! I mean, yes please!","TWN":"……好哇！我要玩！不對，請讓我體驗才對！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"제 눈으로 직접 봐야겠어요! 그 스트리트 카운터의 차기작이라는 걸……!","JPN":"直接自分の目で見ないと！　そのストリート・カウンターの続編とやらを……！","ENG":"I need to see this for myself. The sequel of Street Counter...!","TWN":"我要親眼看看！街頭制裁者的續作……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};